674 bool GlobalMergeImpl::run(Module &M) {
675   if (!EnableGlobalMerge)
676     return false;
677 
678   IsMachO = M.getTargetTriple().isOSBinFormatMachO();
679 
680   auto &DL = M.getDataLayout();
681   MapVector<std::tuple<unsigned, StringRef, Comdat *>,
682             SmallVector<GlobalVariable *, 0>>
683       Globals, ConstGlobals, BSSGlobals;
684   bool Changed = false;
685   setMustKeepGlobalVariables(M);
686 
687   LLVM_DEBUG({
688       dbgs() << "Number of GV that must be kept:  " <<
689                 MustKeepGlobalVariables.size() << "\n";
690       for (const GlobalVariable *KeptGV : MustKeepGlobalVariables)
691         dbgs() << "Kept: " << *KeptGV << "\n";
692   });
693   // Grab all non-const globals.
694   for (auto &GV : M.globals()) {
695     // Merge is safe for "normal" internal or external globals only
696     if (GV.isDeclaration() || GV.isThreadLocal() || GV.hasImplicitSection())
697       continue;
698 
699     // It's not safe to merge globals that may be preempted
700     if (TM && !TM->shouldAssumeDSOLocal(&GV))
701       continue;
702 
703     if (!(Opt.MergeExternal && GV.hasExternalLinkage()) &&
704         !GV.hasLocalLinkage())
705       continue;
706 
707     PointerType *PT = dyn_cast<PointerType>(GV.getType());
708     assert(PT && "Global variable is not a pointer!");
709 
710     unsigned AddressSpace = PT->getAddressSpace();
711     StringRef Section = GV.getSection();
712 
713     // On Mach-O, some section names have special semantics. Don't merge these.
714     if (IsMachO && isSpecialMachOSection(Section))
715       continue;
716 
717     // Ignore all 'special' globals.
718     if (GV.getName().starts_with("llvm.") ||
719         GV.getName().starts_with(".llvm.") || Section == "llvm.metadata")
720       continue;
721 
722     // Ignore all "required" globals:
723     if (isMustKeepGlobalVariable(&GV))
724       continue;
725 
726     // Don't merge tagged globals, as each global should have its own unique
727     // memory tag at runtime. TODO(hctim): This can be relaxed: constant globals
728     // with compatible alignment and the same contents may be merged as long as
729     // the globals occupy the same number of tag granules (i.e. `size_a / 16 ==
730     // size_b / 16`).
731     if (GV.isTagged())
732       continue;
733 
734     // Don't merge globals with metadata other than !dbg, as this is essentially
735     // equivalent to adding metadata to an existing global, which is not
736     // necessarily a correct transformation depending on the specific metadata's
737     // semantics. We will later use copyMetadata() to copy metadata from
738     // component globals to the combined global, which only knows how to do this
739     // correctly for !dbg (and !type, but by this point LowerTypeTests will have
740     // already run).
741     if (GV.hasMetadataOtherThanDebugLoc())
742       continue;
743 
744     Type *Ty = GV.getValueType();
745     TypeSize AllocSize = DL.getTypeAllocSize(Ty);
746     bool CanMerge = AllocSize < Opt.MaxOffset && AllocSize >= Opt.MinSize;
747     if (CanMerge) {
748       if (TM &&
749           TargetLoweringObjectFile::getKindForGlobal(&GV, *TM).isBSS())
750         BSSGlobals[{AddressSpace, Section, GV.getComdat()}].push_back(&GV);
751       else if (GV.isConstant())
752         ConstGlobals[{AddressSpace, Section, GV.getComdat()}].push_back(&GV);
753       else
754         Globals[{AddressSpace, Section, GV.getComdat()}].push_back(&GV);
755     }
756     LLVM_DEBUG(dbgs() << "GV " << (CanMerge ? "" : "not ") << "to merge: " << GV
757                       << "\n");
758   }
759 
760   for (auto &P : Globals)
761     if (P.second.size() > 1)
762       Changed |= doMerge(P.second, M, false, std::get<0>(P.first));
763 
764   for (auto &P : BSSGlobals)
765     if (P.second.size() > 1)
766       Changed |= doMerge(P.second, M, false, std::get<0>(P.first));
767 
768   if (Opt.MergeConstantGlobals)
769     for (auto &P : ConstGlobals)
770       if (P.second.size() > 1)
771         Changed |= doMerge(P.second, M, true, std::get<0>(P.first));
772 
773   return Changed;
774 }
